import{createHmac,timingSafeEqual}from'crypto';import{BadGatewayException,ForbiddenException,Injectable,NotFoundException,ServiceUnavailableException}from'@nestjs/common';import{ConfigService}from'@nestjs/config';import{Prisma}from'@prisma/client';import{PrismaService}from'../prisma/prisma.service';
@Injectable()export class PersonaService{constructor(private readonly config:ConfigService,private readonly db:PrismaService){}get configured(){return Boolean(this.config.get('PERSONA_API_KEY')&&this.config.get('PERSONA_TEMPLATE_ID')&&this.config.get('PERSONA_WEBHOOK_SECRET'))}
 async create(userId:string){if(!this.configured)throw new ServiceUnavailableException('Automated identity verification is not configured');const vendor=await this.db.vendorProfile.findUnique({where:{userId}});if(!vendor)throw new NotFoundException('Vendor application not found');const response=await fetch('https://api.withpersona.com/api/v1/inquiries',{method:'POST',headers:{Authorization:`Bearer ${this.config.get('PERSONA_API_KEY')}`,'Content-Type':'application/json','Persona-Version':this.config.get('PERSONA_API_VERSION')??'2023-01-05','Idempotency-Key':`socialconnect-${vendor.id}`},body:JSON.stringify({data:{attributes:{'inquiry-template-id':this.config.get('PERSONA_TEMPLATE_ID'),'reference-id':vendor.id}}}),signal:AbortSignal.timeout(15000)});if(!response.ok)throw new BadGatewayException('Identity provider inquiry creation failed');const result=await response.json()as any,inquiryId=result.data?.id,url=result.meta?.['one-time-link']??result.meta?.['one-time-link-short'];if(!inquiryId||!url)throw new BadGatewayException('Identity provider returned an incomplete inquiry');await this.db.vendorProfile.update({where:{id:vendor.id},data:{identityProvider:'PERSONA',identityInquiryId:inquiryId,identityStatus:String(result.data?.attributes?.status??'created').toUpperCase(),identityUpdatedAt:new Date()}});return{inquiryId,url}}
 verify(raw:Buffer,header?:string){const secret=this.config.get<string>('PERSONA_WEBHOOK_SECRET');if(!secret||!header)throw new ForbiddenException('Missing identity webhook signature');const pairs=header.split(' '),timestamp=pairs[0]?.match(/(?:^|,)t=(\d+)/)?.[1],signatures=pairs.map(pair=>pair.match(/(?:^|,)v1=([a-f\d]+)/i)?.[1]).filter((value):value is string=>Boolean(value));if(!timestamp||Math.abs(Date.now()/1000-Number(timestamp))>300)throw new ForbiddenException('Stale identity webhook signature');const expected=createHmac('sha256',secret).update(`${timestamp}.${raw.toString('utf8')}`).digest('hex'),valid=signatures.some(value=>value.length===expected.length&&timingSafeEqual(Buffer.from(value.toLowerCase()),Buffer.from(expected)));if(!valid)throw new ForbiddenException('Invalid identity webhook signature')}
 async webhook(body:any){const eventId=String(body?.data?.id??''),eventType=String(body?.data?.attributes?.name??body?.data?.type??''),inquiry=body?.data?.attributes?.payload?.data??body?.data?.attributes?.payload??body?.included?.find?.((item:any)=>item.type==='inquiry'),inquiryId=String(inquiry?.id??''),status=this.status(eventType,inquiry?.attributes?.status);if(!eventId||!eventType)throw new ForbiddenException('Invalid identity webhook');const event=await this.db.identityWebhookEvent.upsert({where:{provider_eventId:{provider:'PERSONA',eventId}},create:{provider:'PERSONA',eventId,eventType,inquiryId:inquiryId||null,payload:body as Prisma.InputJsonObject},update:{}});if(event.processedAt)return{received:true,duplicate:true};try{if(inquiryId&&status){const updated=await this.db.vendorProfile.updateMany({where:{identityInquiryId:inquiryId},data:{identityStatus:status,identityUpdatedAt:new Date()}});if(!updated.count)throw new NotFoundException('Identity inquiry is not linked to a vendor')}await this.db.identityWebhookEvent.update({where:{id:event.id},data:{processedAt:new Date(),error:null}});return{received:true,duplicate:false}}catch(error){await this.db.identityWebhookEvent.update({where:{id:event.id},data:{error:error instanceof Error?error.message:'Identity webhook failed'}});throw error}}
 private status(type:string,fallback?:string){const value=type.toLowerCase();if(value.endsWith('.approved'))return'VERIFIED';if(value.endsWith('.declined')||value.endsWith('.failed'))return'FAILED';if(value.endsWith('.completed'))return'COMPLETED';return fallback?String(fallback).toUpperCase():null}}
